    for (mask in 0 until (1 shl n)) {
        val bits = mask.toString(2).toCharArray()
        val count = bits.count { it == '1' }
        if (count % 3 != 0) continue

        val a = mutableListOf<Long>()
        val b = mutableListOf<Long>()
        val c = mutableListOf<Long>()

        for (i in 0 until n) {
            if ((mask shr i) and 1 == 1) {
                when (count / 3) {
                    1 -> a.add(nums[i])
                    2 -> b.add(nums[i])
                    3 -> c.add(nums[i])
                }
            }
        }

        val xorA = a.fold(0L) { acc, num -> acc xor num }
        val andB = b.fold(0L) { acc, num -> acc and num }
        val xorC = c.fold(0L) { acc, num -> acc xor num }

        dp[mask] = xorA + andB + xorC
    }

    var maxVal = 0L
    for (mask in 0 until (1 shl n)) {
        if (mask.toString(2).count { it == '1' } % 3 == 0) {
            maxVal = maxOf(maxVal, dp[mask])
        }
    }

    return maxVal
}
